class Solution {
public:
    int minChanges(vector<int>& nums, int k) {
        int n = nums.size();
        vector<int> count(1 << 10, 0);
        int max_cnt = 0;
        for (int i = 0; i < k; i++) {
            count.assign(1 << 10, 0);
            int max_cnt_local = 0;
            for (int j = i; j < n; j += k) {
                count[nums[j]]++;
                max_cnt_local = max(max_cnt_local, count[nums[j]]);
            }
            max_cnt += max_cnt_local;
        }
        return n - max_cnt;
    }
};
efficiency: HIGH
time complexity: O(n)
space complexity: O(1)
energy implications: LOW
explanation: The main approach is to count the occurrences of each number at each position modulo k, and then find the maximum count for each position. The key strength is that it takes advantage of the fact that the XOR of a segment of size k is zero if and only if the numbers at the same position modulo k are the same. The weakness is that it assumes that the numbers are less than 2^10.
